// Extract data from either $json or $json.body
const name = $input.item.json.name || $input.item.json.body?.name || '';
const emailRaw = $input.item.json.email || $input.item.json.body?.email;
const interests = $input.item.json.interests || $input.item.json.body?.interests || [];
const message = $input.item.json.message || $input.item.json.body?.message || '';
const timestamp = $input.item.json.timestamp || $input.item.json.body?.timestamp;
const source = $input.item.json.source || $input.item.json.body?.source || 'website';

if (!emailRaw) {
  throw new Error('Email is required');
}

if (!name) {
  throw new Error('Name is required');
}

const email = emailRaw.toLowerCase().trim();

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  throw new Error('Invalid email format');
}

// Extract domain
const domain = email.split('@')[1];

// Create lead ID
const now = new Date();
const dateStr = now.toISOString().slice(0,10).replace(/-/g, '');
const timeStr = now.toTimeString().slice(0,8).replace(/:/g, '');
const namePart = name.replace(/\s+/g, '-').toLowerCase().slice(0, 20);
const leadId = `${dateStr}-${timeStr}-${namePart}`;

// Format date and time
const date = now.toISOString().slice(0,10);
const time = now.toTimeString().slice(0,8);

// Convert interests array to comma-separated string
const interestsString = Array.isArray(interests) ? interests.join(', ') : interests;

return {
  json: {
    lead_id: leadId,
    name: name,
    email: email,
    domain: domain,
    interests: interestsString,
    message: message,
    timestamp: timestamp || now.toISOString(),
    source: source,
    date_submitted: date,
    time_submitted: time,
    status: 'New'
  }
};
